      'postRequest': "window.postRequest = async (event) => { \nawait (async () => {\n    let code = undefined;\n    let msg = undefined;\n    let body = window.$genInitFromSchema('app.structures.LCAPErrorResponse',undefined);\n    let evt = window.$genInitFromSchema('{body: nasl.core.String, status: nasl.core.String}',undefined);\n\nawait (async () => {\n            'use JSBlock';\nevt = event;\n        })();\nbody = this.$genInitFromSchema('app.structures.LCAPErrorResponse', await (JSON.parse((evt || {}).body)))\nawait (async () => {\n            'use JSBlock';\nif(body){\n    code = body.Code\n    msg = ((event.requestInfo || {}).config || {}).errorMessage || body.msg || body.message || body.Message || '系统错误，请查看日志'\n}\n        })();\nawait (console['info'](this.$utils['ToString']('nasl.core.String', this.$utils['ToString']('nasl.core.String', code))))\nif (this.$utils['HasValue']({ type: 'nasl.core.String', value: (body || {}).ErrorType })) {\nawait (console['error'](this.$utils['ToString']('nasl.core.String', this.$utils['ToString']('nasl.core.String', msg))))\n{let it = (body || {}).Data;\nif (this.$isInstanceOf(it, 'nasl.error.SystemIllegalArgumentError')) {\n/* TODO: 此分支用来处理参数错误场景 */\n}\nelse if (this.$isInstanceOf(it, 'nasl.error.AuthUnAuthorizedError')) {\n/* TODO: 此分支对应当前用户没有登录，可设置跳转登录页 */\n}\nelse if (this.$isInstanceOf(it, 'nasl.error.AuthPermissionDeniedError')) {\n/* TODO: 此分支用来处理没有权限的操作 */\n}\nelse {\n}\n}\n}     else {\n/* 判断当前HTTP状态码是否为200 */\nif (((evt || {}).status) == ($i18n.t('b3319f2343bd4afdb3cd327998b64d01'))) {\n}         else {\n/* 非200，则说明发生异常 */\nawait (this.$global.showMessage(this.$utils['ToString']('nasl.core.String', this.$utils['ToString']('nasl.core.String', msg))))\nawait (console['error'](this.$utils['ToString']('nasl.core.String', this.$utils['ToString']('nasl.core.String', msg))))\n}\n\n}\n\n\n})();\n}\n",'beforeRouter': "window.beforeRouter = async (event) => { \nawait (async () => {\n    ;\n\n/* 本逻辑为H5端事件逻辑——如无必要，请勿删改\n\n本逻辑作用：\n\n当H5端页面切换前，会执行本事件逻辑\n\n判断当前访问用户是否对即将访问的页面具有权限，如无权限则跳转处理。\n\n如有需要，开发者可变更处理方式\n */\nawait (async () => {\n            \r\n'use JSBlock'\r\n\r\ntry {\r\n   const uinfo = await this.$auth.getUserInfo()\r\n   console.log('user', uinfo)\r\n} catch (err) {\r\n    console.log(err);\r\n}\r\n\r\nconst { router, routes, authResourcePaths,\r\n    appConfig, beforeRouter, filterRoutes,\r\n    to, from, next, parsePath, getBasePath, filterAuthResources, findNoAuthView, baseResourcePaths } = event;\r\n\r\nfunction concatResourcesRoutes(resources, baseRoutes) {\r\n    return resources.concat(baseRoutes.map((route) => ({\r\n        resourceValue: route,\r\n        // 如果后续需要区分路由类型，这里也需要补充 resourceType\r\n    })));\r\n}\r\n\r\nconst normalizePath = path => path.endsWith('/') ? path : `${path}/`;\r\n\r\nfunction addAuthRoutes(resources) {\r\n    if (Array.isArray(resources) && resources.length) {\r\n        const userResourcePaths = (resources || []).map((resource) => resource && resource.resourceValue || resource && resource.ResourceValue);\r\n        const otherRoutes = filterRoutes(routes, null, (route, ancestorPaths) => {\r\n            const routePath = route.path;\r\n            const completePath = [...ancestorPaths, routePath].join('/');\r\n            const authPath = userResourcePaths.find((userResourcePath) => {\r\n                if (userResourcePath) {\r\n                    const l1 = normalizePath(userResourcePath).split('/');\r\n                    const l2 = normalizePath(completePath).split('/');\r\n                    let bool = true;\r\n                    \r\n                    for (let i = 0; i < l2.length; i++) {\r\n                        if (l2[i] !== l1[i]) {\r\n                            bool = false;\r\n                            break;\r\n                        }\r\n                    }\r\n\r\n                    return bool;\r\n                }\r\n\r\n                return false\r\n            });\r\n            return authPath;\r\n        });\r\n\r\n        otherRoutes.forEach((route) => {\r\n            router.addRoute(route);\r\n        });\r\n    }\r\n}\r\n\r\nconst userInfo = this.$global.userInfo || {};\r\nconst $auth = this.$auth;\r\nconst redirectedFrom = parsePath(to.redirectedFrom);\r\nconst toPath = redirectedFrom && redirectedFrom.path || to.path;\r\nconst toQuery = to.query;\r\nconst authPath = authResourcePaths.find((authResourcePath) => {\r\n    if (authResourcePath === toPath || `${authResourcePath}/` === toPath) {\r\n        return true;\r\n    }\r\n    return false;\r\n});\r\nconst noAuthView = findNoAuthView(routes);\r\n\r\nif (authPath) {\r\n    if (!userInfo.UserId) {\r\n        localStorage.setItem('beforeLogin', JSON.stringify(location));\r\n        \r\n        return next({ \r\n            path: `${getBasePath()}/login` \r\n        });\r\n    } \r\n\r\n    if (!$auth.isInit()) {\r\n        const resources = await $auth.getUserResources(appConfig.domainName);\r\n        const realResources = filterAuthResources(concatResourcesRoutes(resources, baseResourcePaths));\r\n        addAuthRoutes(realResources);\r\n\r\n        return next({\r\n            path: toPath,\r\n            query: toQuery,\r\n            replace: true,\r\n        });\r\n    }\r\n\r\n    if (redirectedFrom && to.path === `${getBasePath()}/notFound`) {\r\n        return next(noAuthView.path ? {\r\n            path: noAuthView.path \r\n        } : undefined);\r\n    }\r\n\r\n    return next();\r\n}\r\n\r\nnext();\n        })();\n\n})();\n}\n"
